-- Program: Kettlebell Flow
-- Category: Equipment-Specific -> equipment_specific
-- Priority: high
-- Durations: [1, 2, 4], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Kettlebell Flow',
    'Continuous kettlebell movement sequences linking fundamental KB exercises into fluid flows. Develops coordination, grip endurance, and full-body conditioning through seamless transitions between swings, cleans, presses, snatches, and carries.',
    'equipment_specific',
    'all_levels',
    4,
    5,
    'circuit',
    ARRAY['Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance', 'Improve VO2 max']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Kettlebell Flow - 1w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'Kettlebell Flow - 1w 4x/wk',
    'equipment_specific',
    4,
    60,
    ARRAY['Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance', 'Improve VO2 max']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Kettlebell Flow'
ON CONFLICT DO NOTHING;

